.side-head.overall{border-color:color-mix(in srgb,var(--_ok) 42%,var(--_line));box-shadow:inset 0 3px 0 var(--_ok),0 8px 24px color-mix(in srgb,var(--_ok) 9%,transparent)}
.side-name{color:var(--_text);font-size:19px;font-weight:780;letter-spacing:-.02em;line-height:1.2}
.side-note{margin-top:7px;color:var(--_muted);font-size:12px;line-height:1.4}
.score{margin-top:12px;color:var(--_muted);font-size:11px;font-weight:750;letter-spacing:.04em;text-transform:uppercase}
.versus{display:flex;align-items:center;justify-content:center}
.versus span{display:flex;width:54px;height:54px;align-items:center;justify-content:center;border:1px solid var(--_line);border-radius:50%;background:var(--_bg);color:var(--_muted);font-size:12px;font-weight:850;letter-spacing:.11em;box-shadow:0 8px 20px rgba(15,23,42,.08)}
.pill{display:inline-flex;align-items:center;gap:5px;width:max-content;margin:0 auto 10px;padding:4px 9px;border-radius:999px;font-size:10px;font-weight:850;letter-spacing:.03em;line-height:1.3}
.pill.ok{background:color-mix(in srgb,var(--_ok) 12%,var(--_bg));color:var(--_ok)}
.group{padding:9px 24px;border-top:1px solid var(--_line);border-bottom:1px solid var(--_line);background:var(--_group);color:var(--_muted);font-size:10px;font-weight:850;letter-spacing:.12em;text-transform:uppercase}
.metric-row{min-height:82px;border-bottom:1px solid var(--_line)}
.metric-row:last-child{border-bottom:0}
.metric-cell,.metric-label{display:flex;align-items:center;justify-content:center;padding:15px 18px;text-align:center;font-variant-numeric:tabular-nums}
.metric-cell{position:relative;background:var(--_bg);color:var(--_text);font-size:14px;font-weight:700}
.metric-cell:first-child{border-right:1px solid var(--_line)}
.metric-cell:last-child{border-left:1px solid var(--_line)}
.metric-cell.wins{background:color-mix(in srgb,var(--_ok) 8%,var(--_bg));box-shadow:inset 0 -2px 0 color-mix(in srgb,var(--_ok) 70%,transparent);color:var(--_ok)}
.win-tag{position:absolute;top:7px;right:8px;color:var(--_ok);font-size:8px;font-weight:900;letter-spacing:.1em;text-transform:uppercase}
.metric-label{flex-direction:column;background:var(--_soft);color:var(--_text);font-size:12px;font-weight:750;line-height:1.3}
.metric-note{margin-top:4px;color:var(--_muted);font-size:10px;font-weight:550}
.mark{display:inline-flex;min-width:28px;height:28px;align-items:center;justify-content:center;border-radius:999px;font-size:16px;font-weight:850;line-height:1}
.mark.yes{background:color-mix(in srgb,var(--_ok) 12%,var(--_bg));color:var(--_ok)}
.mark.no{background:color-mix(in srgb,var(--_no) 11%,var(--_bg));color:var(--_no)}
.mark.partial{min-width:auto;padding:0 10px;background:color-mix(in srgb,var(--_partial) 13%,var(--_bg));color:var(--_partial);font-size:11px;letter-spacing:.02em}
.rating{display:inline-flex;align-items:baseline;gap:5px}
.star{color:#f59e0b}.out-of{color:var(--_muted);font-size:10px;font-weight:600}
.empty{padding:42px 24px;color:var(--_muted);font-size:14px;text-align:center}
@media (max-width:520px){.heading{padding:18px 18px 16px}.matchup{padding:16px 18px}.group{padding-right:18px;padding-left:18px}}
@media (prefers-color-scheme:dark){:host{--_bg:var(--ov-bg,#0f172a);--_raised:var(--ov-bg,#111827);--_text:var(--ov-text,#e5e7eb);--_muted:var(--ov-muted,#9ca3af);--_line:var(--ov-line,#293548);--_accent:var(--ov-accent,#818cf8);--_ok:var(--ov-ok,#34d399);--_no:var(--ov-no,#fb7185);--_partial:var(--ov-partial,#fbbf24);--_soft:#111827;--_group:#182235;--_accent-soft:#1b2145;--_hover:#172033}.frame{box-shadow:0 14px 34px rgba(0,0,0,.28)}}

`;
const sheet = new CSSStyleSheet(); sheet.replaceSync(CSS); root.adoptedStyleSheets=[sheet];

const make = (tag,className,text) => { const node=document.createElement(tag); if(className) node.className=className; if(text!==undefined) node.textContent=text; return node; };
const items=Array.isArray(data.items)?data.items.slice(0,2):[];
const rows=Array.isArray(data.rows)?data.rows:[];
const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Head-to-head';
const winCounts=[0,0];
rows.forEach((row) => { if(row&&row.winner===0) winCounts[0]+=1; if(row&&row.winner===1) winCounts[1]+=1; });
let overall=data.winner;
if(overall!==0&&overall!==1&&overall!=='tie') overall=winCounts[0]===winCounts[1]?'tie':(winCounts[0]>winCounts[1]?0:1);
const frame=make('section','frame'); frame.setAttribute('aria-label',title);
const heading=make('header','heading');
heading.appendChild(make('div','eyebrow','Head to head'));
heading.appendChild(make('h2','',title));
if(data.subtitle) heading.appendChild(make('div','meta',String(data.subtitle)));
frame.appendChild(heading);
if(items.length!==2||!rows.length){
  frame.appendChild(make('div','empty','Add exactly two items and at least one comparison row.'));
}else{
  const scroll=make('div','scroll'); const duel=make('div','duel');
  const matchup=make('div','matchup');
  items.forEach((item,index) => {
    if(index===1) matchup.appendChild(make('div','versus')).appendChild(make('span','',data.versusLabel?String(data.versusLabel):'VS'));
    const side=make('article','side-head'+(overall===index?' overall':''));
    if(overall===index) side.appendChild(make('span','pill ok','✓ Overall winner'));
    side.appendChild(make('div','side-name',item&&item.name!=null?String(item.name):'Untitled'));
    if(item&&item.note) side.appendChild(make('div','side-note',String(item.note)));
    side.appendChild(make('div','score',winCounts[index]+' row win'+(winCounts[index]===1?'':'s')));
    matchup.appendChild(side);
  });
  duel.appendChild(matchup);
  let previousGroup=null;
  const renderValue=(cell,kind) => {
    const wrap=make('span','');
    if(kind==='bool'){
      if(cell===true){ const mark=make('span','mark yes','✓'); mark.setAttribute('aria-label','Yes'); return mark; }
      if(cell===false){ const mark=make('span','mark no','✗'); mark.setAttribute('aria-label','No'); return mark; }
      if(cell==='partial'){ const mark=make('span','mark partial','Partial'); mark.setAttribute('aria-label','Partial'); return mark; }
      wrap.textContent='—'; return wrap;
    }
    if(kind==='rating'){
      if(typeof cell==='number'&&Number.isFinite(cell)){
        const score=Math.max(0,Math.min(5,cell)); const rating=make('span','rating'); rating.setAttribute('aria-label',score+' out of 5');
        rating.appendChild(make('span','star','★')); rating.appendChild(make('span','',Number.isInteger(score)?String(score):score.toFixed(1))); rating.appendChild(make('span','out-of','/ 5')); return rating;
      }
      wrap.textContent='—'; return wrap;
    }
    wrap.textContent=cell===null||cell===undefined||cell===''?'—':String(cell); return wrap;
  };
  rows.forEach((row) => {
    const group=row&&typeof row.group==='string'?row.group.trim():'';
    if(group&&group!==previousGroup) duel.appendChild(make('div','group',group));
    previousGroup=group;
    const metric=make('div','metric-row'); const values=row&&Array.isArray(row.values)?row.values:[];
    [0,1].forEach((index) => {
      if(index===1){
        const label=make('div','metric-label'); label.appendChild(make('span','',row&&row.label!=null?String(row.label):'Untitled metric'));
        if(row&&row.note) label.appendChild(make('span','metric-note',String(row.note))); metric.appendChild(label);
      }
      const cell=make('div','metric-cell'+(row&&row.winner===index?' wins':''));
      if(row&&row.winner===index) cell.appendChild(make('span','win-tag','Win'));
      cell.appendChild(renderValue(values[index],row&&row.kind?row.kind:'text')); metric.appendChild(cell);
    });
    duel.appendChild(metric);
  });
  scroll.appendChild(duel); frame.appendChild(scroll);
}
root.appendChild(frame);
parent.appendChild(host);
